def get_db():
    conn = sqlite3.connect('app.db')
    conn.row_factory = sqlite3.Row
    return conn


def cache_key_generator(*args, **kwargs):
    key_data = str(args) + str(sorted(kwargs.items()))
    return hashlib.md5(key_data.encode()).hexdigest()


def cache_db_query(ttl=300):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"db_query:{func.__name__}:{cache_key_generator(*args, **kwargs)}"
            
            cached_result = memcache_client.get(cache_key)
            if cached_result is not None:
                return cached_result
            
            result = func(*args, **kwargs)
            
            memcache_client.set(cache_key, result, expire=ttl)
            
            return result
        return wrapper
    return decorator


def cache_api_response(ttl=60):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"api:{request.path}:{request.method}:{cache_key_generator(request.args.to_dict())}"
            
            cached_response = memcache_client.get(cache_key)
            if cached_response is not None:
                return cached_response
            
            response = func(*args, **kwargs)
            
            memcache_client.set(cache_key, response, expire=ttl)
            
            return response
        return wrapper
    return decorator


